SELECT cur.order_sn AS orderSn, COALESCE(SUM( (hist.price - cur.price) * COALESCE(cur.quantity_entry, cur.quantity_real) ), 0) AS costReduction FROM erp_purchase_order_item cur JOIN erp_purchase_order cur_o ON cur_o.order_sn = cur.order_sn LEFT JOIN ( SELECT i2.sku, i2.order_sn AS exclude_order_sn, i2.price, o2.opt_realname, o2.lx_create_time, ROW_NUMBER() OVER (PARTITION BY i2.sku, i2.order_sn ORDER BY o2.lx_create_time DESC) AS rn FROM erp_purchase_order_item i2 JOIN erp_purchase_order o2 ON o2.order_sn = i2.order_sn ) hist ON hist.sku = cur.sku AND hist.exclude_order_sn != cur.order_sn AND hist.opt_realname = cur_o.opt_realname AND hist.lx_create_time < cur_o.lx_create_time AND hist.rn = 1 WHERE cur.order_sn IN
#{sn}
AND (cur.item_status IS NULL OR cur.item_status != 2) GROUP BY cur.order_sn

SELECT i.price, o.lx_create_time AS purchaseDate
FROM erp_purchase_order_item i
JOIN erp_purchase_order o ON o.order_sn = i.order_sn
WHERE i.sku = #{sku}
  AND i.order_sn != #{excludeOrderSn}
  AND o.opt_realname = #{optRealname}
  AND o.lx_create_time < #{purchaseDateBefore}
ORDER BY o.lx_create_time ASC
LIMIT #{limit}

SELECT i.price
FROM erp_purchase_order_item i
JOIN erp_purchase_order o ON o.order_sn = i.order_sn
WHERE i.sku = #{sku}
  AND i.order_sn != #{excludeOrderSn}
  AND o.opt_realname = #{optRealname}
  AND o.lx_create_time < #{purchaseDateBefore}
ORDER BY o.lx_create_time ASC
LIMIT 1

SELECT i.price
FROM erp_purchase_order_item i
JOIN erp_purchase_order o ON o.order_sn = i.order_sn
WHERE i.sku = #{sku}
  AND i.order_sn != #{excludeOrderSn}
  AND o.opt_realname = #{optRealname}
  AND o.lx_create_time < #{purchaseDateBefore}
  AND o.deleted = 0
  AND i.deleted = 0
ORDER BY o.lx_create_time ASC
